import React, { useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import "../styles/Header.css";

export default function Header() {
    const navigate = useNavigate();
    const [isDarkMode, setIsDarkMode] = useState(false);

    const toggleTheme = () => {
        setIsDarkMode(!isDarkMode);
        if (!isDarkMode) {
            // Applique les variables du thème sombre
            document.documentElement.style.setProperty('--background-color', '#1e1e1e');
            document.documentElement.style.setProperty('--text-color', '#ffffff');
            document.documentElement.style.setProperty('--button-bg', '#333333');
            document.documentElement.style.setProperty('--button-text', '#ffffff');
            document.documentElement.style.setProperty('--primary-color', '#f0f0f0');
            document.documentElement.style.setProperty('--secondary-color', '#2a2a2a');
        } else {
            // Applique les variables du thème clair
            document.documentElement.style.setProperty('--primary-color', '#EC361E');
            document.documentElement.style.setProperty('--secondary-color', '#FCF9CE');
        }
    };

    return (
        <header className="Header">
            <nav className="Navbar">
                <div className="Liste">
                    <a className="Liste-link">Portfolio</a>
                    <a className="Liste-link">CV</a>
                </div>
                <div className="Titles">
                    <Link to="/" className="Title-link">GRENOT BASTIEN</Link>
                </div>
                <div className="Social">
                    <a href="https://www.linkedin.com/in/bastiengrnt/" target="_blank" rel="noreferrer">
                        <img src="/Logo/linkedin.svg" alt="LinkedIn"/>
                    </a>
                    <a href="https://github.com/BastienGRNT" target="_blank" rel="noreferrer">
                        <img src="/Logo/github.svg" alt="Github"/>
                    </a>
                    <a href="mailto:bastien.grenot@gmail.com" target="_blank" rel="noreferrer">
                        <img src="/Logo/gmail.svg" alt="Email"/>
                    </a>
                    {/* Bouton switch de thème */}
                    <div className="themeChecker">
                        <label className="theme-switch">
                            <input
                                className="toggle-checkbox"
                                type="checkbox"
                                checked={isDarkMode}
                                onChange={toggleTheme}
                            />
                            <div className="toggle-slot">
                                <div className="sun-icon-wrapper">
                                    <div className="iconify sun-icon" data-icon="feather-sun" data-inline="false"></div>
                                </div>
                                <div className="toggle-button"></div>
                                <div className="moon-icon-wrapper">
                                    <div className="iconify moon-icon" data-icon="feather-moon" data-inline="false"></div>
                                </div>
                            </div>
                        </label>
                    </div>
                </div>
            </nav>
        </header>
    );
}
